1	package config
2	
3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/http"
8		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/policies"
9		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/nginx/config/shared"
10		"github.com/nginx/nginx-gateway-fabric/v2/internal/controller/state/dataplane"
11		"github.com/nginx/nginx-gateway-fabric/v2/internal/framework/helpers"
12	)
13	
14	// createIncludeExecuteResultsFromServers creates a list of executeResults -- or NGINX config files -- from all
15	// the includes in the provided servers. Since there may be duplicate includes, such as configuration for policies that
16	// apply to multiple routes, or snippets filters that are attached to multiple routing rules, this function deduplicates
17	// all includes, ensuring only a single file per unique include is generated.
18	func createIncludeExecuteResultsFromServers(servers []http.Server) []executeResult {
19		uniqueIncludes := make(map[string][]byte)
20	
21		// deduplicate include files across servers and location
22		for _, server := range servers {
23			for _, include := range server.Includes {
24				uniqueIncludes[include.Name] = include.Content
25			}
26	
27			for _, loc := range server.Locations {
28				for _, include := range loc.Includes {
29					uniqueIncludes[include.Name] = include.Content
30				}
31			}
32		}
33	
34		results := make([]executeResult, 0, len(uniqueIncludes))
35	
36		for filename, contents := range uniqueIncludes {
37			results = append(results, executeResult{
38				dest: filename,
39				data: contents,
40			})
41		}
42	
43		return results
44	}
45	
46	// createIncludesFromPolicyGenerateResult converts a list of policies.File into a list of includes.
47	func createIncludesFromPolicyGenerateResult(resFiles []policies.File) []shared.Include {
48		if len(resFiles) == 0 {
49			return nil
50		}
51	
52		includes := make([]shared.Include, 0, len(resFiles))
53		for _, file := range resFiles {
54			includes = append(includes, shared.Include{
55				Name:    includesFolder + "/" + file.Name,
56				Content: file.Content,
57			})
58		}
59	
60		return includes
61	}
62	
63	// createIncludeFromSnippet converts a dataplane.Snippet into an include.
64	func createIncludeFromSnippet(snippet dataplane.Snippet) shared.Include {
65		return shared.Include{
66			Name:    includesFolder + "/" + snippet.Name + ".conf",
67			Content: []byte(snippet.Contents),
68		}
69	}
70	
71	// createIncludesFromAuthZConfigs creates include files for AuthZ map configurations.
72	// Each rule's maps are placed in their own include file named:
73	//
74	//	<filter namespace-name>_rule_<index>_require_<all|any>.conf
75	//
76	// The top-level aggregation map is placed in:
77	//
78	//	<filter namespace-name>_authz_require_<all|any>.conf
79	func createIncludesFromAuthZConfigs(authZConfigs []*dataplane.AuthZConfig) []shared.Include {
80		if len(authZConfigs) == 0 {
81			return nil
82		}
83	
84		var includes []shared.Include
85	
86		for _, cfg := range authZConfigs {
87			if cfg == nil {
88				continue
89			}
90	
91			// Create per-rule include files
92			for ruleIdx, ruleMap := range cfg.RuleMaps {
93				if len(ruleMap.Maps) == 0 {
94					continue
95				}
96				includes = append(includes, createIncludeFromAuthZRuleMap(cfg.FilterNsName, ruleIdx, ruleMap))
97			}
98	
99			if cfg.AuthZMap != nil && cfg.AuthZMap.Source != "" {
100				includes = append(includes, createIncludeFromAuthZMap(cfg.FilterNsName, *cfg.AuthZMap))
101			}
102		}
103	
104		return includes
105	}
106	
107	// createIncludeFromAuthZRuleMap creates an include file for a single AuthZ rule map.
108	func createIncludeFromAuthZRuleMap(filterNsName string, ruleIdx int, ruleMap dataplane.AuthZRuleMap) shared.Include {
109		fileName := fmt.Sprintf(
110			"%s/%s_rule_%d_require_%s.conf",
111			includesFolder, filterNsName, ruleIdx, strings.ToLower(string(ruleMap.Require)),
112		)
113		return shared.Include{
114			Name:    fileName,
115			Content: helpers.MustExecuteTemplate(mapsTemplate, ruleMap.Maps),
116		}
117	}
118	
119	// createIncludeFromAuthZMap creates an include file for a top-level AuthZ map.
120	func createIncludeFromAuthZMap(filterNsName string, authZMap dataplane.AuthZMap) shared.Include {
121		fileName := fmt.Sprintf(
122			"%s/%s_authz_require_%s.conf",
123			includesFolder, filterNsName, strings.ToLower(string(authZMap.Require)),
124		)
125		return shared.Include{
126			Name:    fileName,
127			Content: helpers.MustExecuteTemplate(mapsTemplate, []shared.Map{authZMap.Map}),
128		}
129	}
130	
131	// deduplicateIncludes deduplicates all the includes using the include name as the identifier.
132	// Duplicate includes are possible when a single policy targets multiple resources, or a snippets filter
133	// is referenced on multiple routing rules.
134	func deduplicateIncludes(includes []shared.Include) []shared.Include {
135		uniqueIncludes := make(map[string]shared.Include)
136		for _, i := range includes {
137			if _, ok := uniqueIncludes[i.Name]; !ok {
138				uniqueIncludes[i.Name] = i
139			}
140		}
141	
142		results := make([]shared.Include, 0, len(uniqueIncludes))
143		for _, i := range uniqueIncludes {
144			results = append(results, i)
145		}
146	
147		return results
148	}
149	
150	// createIncludesFromLocationSnippetsFilters creates includes for a location from a list of SnippetsFilters.
151	// A SnippetsFilter can have both a server snippet and a location snippet. This function converts
152	// all the location snippets in the SnippetsFilters to includes.
153	func createIncludesFromLocationSnippetsFilters(filters []dataplane.SnippetsFilter) []shared.Include {
154		if len(filters) == 0 {
155			return nil
156		}
157	
158		includes := make([]shared.Include, 0)
159	
160		for _, f := range filters {
161			if f.LocationSnippet != nil {
162				includes = append(includes, createIncludeFromSnippet(*f.LocationSnippet))
163			}
164		}
165	
166		return deduplicateIncludes(includes)
167	}
168	
169	// createIncludesFromServerSnippetsFilters creates includes for a server from a dataplane.VirtualServer.
170	// It finds all the server snippets from the SnippetsFilters on each MatchRule. This function converts all
171	// the server snippets into includes.
172	func createIncludesFromServerSnippetsFilters(server dataplane.VirtualServer) []shared.Include {
173		if len(server.PathRules) == 0 {
174			return nil
175		}
176	
177		includes := make([]shared.Include, 0)
178	
179		for _, pr := range server.PathRules {
180			for _, mr := range pr.MatchRules {
181				for _, sf := range mr.Filters.SnippetsFilters {
182					if sf.ServerSnippet != nil {
183						includes = append(includes, createIncludeFromSnippet(*sf.ServerSnippet))
184					}
185				}
186			}
187		}
188	
189		return deduplicateIncludes(includes)
190	}
191	
192	// createIncludesFromSnippets converts a list of Snippets to a list of Includes.
193	// Used for main and http snippets only. Server and location snippets are handled by other functions above.
194	func createIncludesFromSnippets(snippets []dataplane.Snippet) []shared.Include {
195		if len(snippets) == 0 {
196			return nil
197		}
